#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* buildTree(vector<int>& inorder, vector<int>& postorder) {
        if (inorder.empty() || postorder.empty()) {
            return nullptr;
        }
        TreeNode* root = new TreeNode(postorder.back());
        int idx = find(inorder.begin(), inorder.end(), postorder.back()) - inorder.begin();
        vector<int> left_inorder(inorder.begin(), inorder.begin() + idx);
        vector<int> right_inorder(inorder.begin() + idx + 1, inorder.end());
        vector<int> left_postorder(postorder.begin(), postorder.begin() + idx);
        vector<int> right_postorder(postorder.begin() + idx, postorder.end() - 1);
        root->left = buildTree(left_inorder, left_postorder);
        root->right = buildTree(right_inorder, right_postorder);
        return root;
    }
    vector<int> preorderTraversal(TreeNode* root) {
        if (!root) {
            return {};
        }
        vector<int> res = {root->val};
        auto left = preorderTraversal(root->left);
        auto right = preorderTraversal(root->right);
        res.insert(res.end(), left.begin(), left.end());
        res.insert(res.end(), right.begin(), right.end());
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> inorder(n);
    for (int i = 0; i < n; i++) cin >> inorder[i];
    int m;
    cin >> m;
    vector<int> postorder(n);
    for (int i = 0; i < n; i++) cin >> postorder[i];
    Solution sol;
    TreeNode* root = sol.buildTree(inorder, postorder);
    auto res = sol.preorderTraversal(root);
    for (int i = 0; i < res.size(); i++) {
        cout << res[i] << (i == res.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
